function candidate(first, second) {
  first = first || ".";
  second = second || ".";

  if (/^(?:data:|[A-Za-z][A-Za-z0-9+.-]*:)/.test(second)) {
    return second;
  }

  function parseLocation(value) {
    var match = /^([A-Za-z][A-Za-z0-9+.-]*:)?(?:\/\/([^/?#]*))?([^?#]*)(\?[^#]*)?(#.*)?$/.exec(value);
    return {
      scheme: match && match[1] ? match[1] : "",
      host: match && match[2] != null ? match[2] : null,
      path: match && match[3] ? match[3] : "",
      query: match && match[4] ? match[4] : "",
      hash: match && match[5] ? match[5] : ""
    };
  }

  function normalize(path) {
    var absolute = path.charAt(0) === "/";
    var trailing = path.length > 1 && path.charAt(path.length - 1) === "/";
    var parts = path.split("/");
    var out = [];

    for (var i = 0; i < parts.length; i++) {
      var part = parts[i];
      if (!part || part === ".") continue;
      if (part === "..") {
        if (out.length && out[out.length - 1] !== "..") {
          out.pop();
        } else if (!absolute) {
          out.push("..");
        }
      } else {
        out.push(part);
      }
    }

    var result = (absolute ? "/" : "") + out.join("/");
    if (!result) result = absolute ? "/" : ".";
    if (trailing && result !== "/") result += "/";
    return result;
  }

  function directoryOf(path) {
    if (!path) return "/";
    if (path.charAt(path.length - 1) === "/") return path;
    var index = path.lastIndexOf("/");
    return index < 0 ? "" : path.slice(0, index + 1);
  }

  var base = parseLocation(first);

  if (second.slice(0, 2) === "//") {
    return (base.scheme || "") + second;
  }

  var nextPath;
  if (second.charAt(0) === "/") {
    nextPath = normalize(second);
  } else if (base.scheme && base.host === "" && !base.path && second.indexOf("/") < 0 && second.charAt(0) !== ".") {
    base.host = second;
    nextPath = "/";
  } else {
    nextPath = normalize(directoryOf(base.path || (base.scheme ? "/" : ".")) + second);
  }

  if (base.scheme || base.host !== null) {
    return base.scheme + (base.host !== null ? "//" + base.host : "") + nextPath + base.query + base.hash;
  }

  return nextPath;
}
